std::pair<int, std::unordered_map<std::string, int>> countUniqueWords(const std::string& input) {
    std::string cleanedInput = input;
    std::unordered_set<std::string> uniqueWords;
    std::unordered_map<std::string, int> wordOccurrences;

    // Convert to lowercase and replace punctuation with spaces
    for (char& c : cleanedInput) {
        if (ispunct(c)) {
            c = ' ';
        } else {
            c = tolower(c);
        }
    }

