def manageEmergencyQueue():
    # Initialize the emergency queue using deque
    emergency_queue = deque()

    def add_patient(patient_id, severity_score):
        """Add a new patient to the queue based on severity"""
        # For empty queue or if new patient has highest priority
        if not emergency_queue or severity_score > emergency_queue[0][1]:
            emergency_queue.appendleft((patient_id, severity_score))
        else:
            # Find the right position based on severity
            for i in range(len(emergency_queue)):
                if severity_score > emergency_queue[i][1]:
                    emergency_queue.insert(i, (patient_id, severity_score))
                    break
            else:
                # If no higher priority found, append to the end
                emergency_queue.append((patient_id, severity_score))
        return emergency_queue.copy()

    def next_patient():
        """Get the highest priority patient"""
        if emergency_queue:
            return emergency_queue.popleft()
        return None

    def update_priority(patient_id, new_severity):
        """Update the priority of a patient still in the queue"""
        # Remove the patient from current position
        for i in range(len(emergency_queue)):
            if emergency_queue[i][0] == patient_id:
                emergency_queue.remove(emergency_queue[i])
                # Add back with updated severity
                add_patient(patient_id, new_severity)
                return True
        return False

    def get_queue():
        """Return the current queue"""
        return list(emergency_queue)

    # Return functions to interact with the queue
    return {
        "add_patient": add_patient,
        "next_patient": next_patient,
        "update_priority": update_priority,
        "get_queue": get_queue
    }

