    recipient: String,
    subject: String,
    body: String,
    timestamp: u64,
    is_urgent: bool,
}

pub fn manage_email_queue(mut queue: VecDeque<Email>, process_count: usize, shuffle_interval: usize) -> VecDeque<Email> {
    let mut processed = 0;
    let mut rng = thread_rng();

    while processed < process_count && !queue.is_empty() {
        // Periodically shuffle to prioritize urgent emails
        if processed % shuffle_interval == 0 && processed > 0 {
            let mut emails: Vec<Email> = queue.drain(..).collect();
            emails.sort_by(|a, b| b.is_urgent.cmp(&a.is_urgent));
            emails.shuffle(&mut rng);
            queue.extend(emails);
        }

        if let Some(email) = queue.pop_front() {
            let current_time = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap()
                .as_secs();

            // Process email and log details
            println!(
                "Processing email - ID: {}, Recipient: {}, Subject: {}, Queued at: {}, Processed at: {}, Wait time: {}s, Urgent: {}",
                email.id,
                email.recipient,
                email.subject,
                email.timestamp,
                current_time,
                current_time - email.timestamp,
                email.is_urgent
            );

            processed += 1;
        }
    }

    queue
}

