std::vector<std::pair<int, int>> mergeMeetingTimes(std::vector<std::pair<int, int>>& intervals) {
    if (intervals.empty()) {
        return {};
    }

    // Create priority queue that sorts intervals by start time
    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, 
                       std::greater<std::pair<int, int>>> pq;

    // Add all intervals to the priority queue
    for (const auto& interval : intervals) {
        pq.push(interval);
    }

    std::vector<std::pair<int, int>> result;

    // Get the first interval
    auto current = pq.top();
    pq.pop();

    // Process all intervals in ascending order of start time
    while (!pq.empty()) {
        auto next = pq.top();
        pq.pop();

        // If current interval overlaps with the next one, merge them
        if (current.second >= next.first) {
            current.second = std::max(current.second, next.second);
        } else {
            // No overlap, add current to result and move to next
            result.push_back(current);
            current = next;
        }
    }

    // Add the last interval
    result.push_back(current);

    return result;
}

