fn manage_student_grades(max_entries: usize) -> impl Fn(StudentAction) -> Result<f32, &'static str> {
    let mut grades: ArrayVec<GradeEntry, 64> = ArrayVec::new();

    move |action| match action {
        StudentAction::Add { student_id, grade } => {
            if grades.len() >= max_entries {
                return Err("Maximum number of entries reached");
            }
            if grade < 0.0 || grade > 100.0 {
                return Err("Grade must be between 0 and 100");
            }
            if grades.iter().any(|entry| entry.student_id == student_id) {
                return Err("Student ID already exists");
            }

            grades.push(GradeEntry { student_id, grade });
            Ok(calculate_average(&grades))
        },

        StudentAction::Update { student_id, grade } => {
            if grade < 0.0 || grade > 100.0 {
                return Err("Grade must be between 0 and 100");
            }

            let entry = grades.iter_mut()
                .find(|entry| entry.student_id == student_id)
                .ok_or("Student ID not found")?;

            entry.grade = grade;
            Ok(calculate_average(&grades))
        },

        StudentAction::Delete { student_id } => {
            let position = grades.iter()
                .position(|entry| entry.student_id == student_id)
                .ok_or("Student ID not found")?;

            grades.remove(position);

            if grades.is_empty() {
                Ok(0.0)
            } else {
                Ok(calculate_average(&grades))
            }
        },

        StudentAction::GetAverage => {
            if grades.is_empty() {
                Ok(0.0)
            } else {
                Ok(calculate_average(&grades))
            }
        },
    }
}

fn calculate_average(grades: &ArrayVec<GradeEntry, 64>) -> f32 {
    if grades.is_empty() {
        return 0.0;
    }

    let sum: f32 = grades.iter().map(|entry| entry.grade).sum();
    sum / grades.len() as f32
}

