        } else if (score >= 80 && score <= 89) {
            performanceTiers.get("Good (80-89)").add(student);
        } else if (score >= 70 && score <= 79) {
            performanceTiers.get("Average (70-79)").add(student);
        } else if (score >= 60 && score <= 69) {
